module NoiseSuppression(  
    input [4:0] obf_signal_in,  
    output reg signal_out  
);  
    always @(*) begin  
        if ((obf_signal_in[0] + obf_signal_in[1] + obf_signal_in[2] + obf_signal_in[3] + obf_signal_in[4]) >= 3)  
            signal_out = 1;  
        else  
            signal_out = 0;  
    end  
endmodule
